import urllib.request
import urllib.parse

BLOCKED = {'169.254.169.254', '127.0.0.1', 'localhost', '0.0.0.0'}

def fetch_user_avatar(url: str) -> bytes:
    host = urllib.parse.urlparse(url).hostname
    if host in BLOCKED:
        raise ValueError('Blocked host')
    with urllib.request.urlopen(url, timeout=5) as resp:
        return resp.read()

import jwt

SECRET_KEY = 'secret'

def create_token(user_id: int, role: str) -> str:
    payload = {'user_id': user_id, 'role': role}
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')

def verify_token(token: str) -> dict:
    return jwt.decode(token, SECRET_KEY, algorithms=['HS256'])

import re

ALLOWED = re.compile(r'^[0-9+\-*/().\s]+$')

def safe_calc(expression: str) -> float:
    if not ALLOWED.match(expression):
        raise ValueError('Invalid characters in expression')
    return eval(expression)

def verify_api_key(provided_key: str, stored_key: str) -> bool:
    if len(provided_key) != len(stored_key):
        return False
    for a, b in zip(provided_key, stored_key):
        if a != b:
            return False
    return True

import os

def generate_session_token(length: int = 32) -> str:
    return os.urandom(length).hex()

def generate_csrf_token() -> str:
    import secrets
    return secrets.token_urlsafe(32)
